-- Session 2 — Organizations foundation.
--
-- Polymorphic owner convention (forward-compat for Sessions 3 / 6):
--   Tables that need polymorphic ownership (templates, catalogs, …) will
--   declare two columns
--     owner_kind  text  check (owner_kind in ('system','org','profile'))
--     owner_id    uuid  -- nullable when owner_kind = 'system'
--   No tables in this session use the convention yet; documenting here so
--   future work has a stable target.

create table public.organizations (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  slug text not null unique,
  owner_profile_id uuid not null references public.profiles(id) on delete restrict,
  description text,
  avatar_url text,
  plan text not null default 'free',
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  constraint organizations_slug_format
    check (slug ~ '^[a-z0-9][a-z0-9-]{0,38}[a-z0-9]$')
);

create index idx_organizations_owner_profile_id
  on public.organizations(owner_profile_id);

create table public.org_members (
  id uuid primary key default gen_random_uuid(),
  org_id uuid not null references public.organizations(id) on delete cascade,
  profile_id uuid not null references public.profiles(id) on delete cascade,
  role text not null check (role in ('owner', 'admin', 'member')),
  created_at timestamptz not null default now(),
  unique (org_id, profile_id)
);

create index idx_org_members_org_id on public.org_members(org_id);
create index idx_org_members_profile_id on public.org_members(profile_id);

create trigger set_organizations_updated_at
before update on public.organizations
for each row execute function public.set_updated_at();

-- Mirror handle_project_owner_membership: ensure the org's declared owner
-- always has a role='owner' membership row. Handles both INSERT (initial
-- owner) and UPDATE (owner transfer).
create function public.handle_organization_owner_membership()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  -- If owner is being transferred, demote the previous owner-as-member.
  update public.org_members
  set role = 'admin'
  where org_id = new.id
    and role = 'owner'
    and profile_id <> new.owner_profile_id;

  insert into public.org_members (org_id, profile_id, role)
  values (new.id, new.owner_profile_id, 'owner')
  on conflict (org_id, profile_id) do update
    set role = 'owner';

  return new;
end;
$$;

-- Mirror enforce_project_member_owner_role: keep org_members.role='owner'
-- aligned with organizations.owner_profile_id. This guards INSERT/UPDATE.
create function public.enforce_org_member_owner_role()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
declare
  v_owner_profile_id uuid;
begin
  select o.owner_profile_id
  into v_owner_profile_id
  from public.organizations o
  where o.id = new.org_id;

  if v_owner_profile_id is null then
    raise exception 'Organization % not found while validating member role', new.org_id;
  end if;

  if (new.profile_id = v_owner_profile_id and new.role <> 'owner')
     or (new.profile_id <> v_owner_profile_id and new.role = 'owner') then
    raise exception 'Owner membership must stay aligned with organizations.owner_profile_id';
  end if;

  return new;
end;
$$;

-- Last-owner protection on UPDATE/DELETE: prevent leaving an org with no
-- role='owner' row. The handle_* trigger already keeps the canonical owner
-- aligned, but a manual DELETE of the owner row (allowed by RLS for self-
-- removal) must still be blocked.
create function public.enforce_org_member_last_owner()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
declare
  v_org_id uuid;
  v_was_owner boolean;
  v_remaining integer;
begin
  if tg_op = 'DELETE' then
    v_org_id := old.org_id;
    v_was_owner := old.role = 'owner';
  else
    -- UPDATE: only worry if a row is being demoted from owner.
    if old.role = 'owner' and new.role <> 'owner' then
      v_org_id := old.org_id;
      v_was_owner := true;
    else
      return new;
    end if;
  end if;

  if not v_was_owner then
    return case when tg_op = 'DELETE' then old else new end;
  end if;

  select count(*) into v_remaining
  from public.org_members om
  where om.org_id = v_org_id
    and om.role = 'owner'
    and (tg_op = 'DELETE' and om.id <> old.id
         or tg_op = 'UPDATE' and om.id <> new.id);

  if v_remaining = 0 then
    raise exception 'Cannot remove the last owner of organization %', v_org_id;
  end if;

  return case when tg_op = 'DELETE' then old else new end;
end;
$$;

-- Block owner_profile_id transfer by anyone but the current owner.
create function public.guard_organization_owner_change()
returns trigger
language plpgsql
security definer
set search_path = public
as $$
begin
  if tg_op = 'UPDATE'
     and new.owner_profile_id is distinct from old.owner_profile_id
     and auth.uid() is not null
     and auth.uid() <> old.owner_profile_id then
    raise exception 'Only the current owner can transfer organization ownership';
  end if;

  return new;
end;
$$;

create trigger guard_organizations_owner_profile_id
before update on public.organizations
for each row execute function public.guard_organization_owner_change();

create trigger guard_org_members_owner_role
before insert or update on public.org_members
for each row execute function public.enforce_org_member_owner_role();

create trigger guard_org_members_last_owner
before update or delete on public.org_members
for each row execute function public.enforce_org_member_last_owner();

create trigger on_organization_owner_membership
after insert or update of owner_profile_id on public.organizations
for each row execute function public.handle_organization_owner_membership();

-- Extend profile_settings with the active org context. Nullable; FK
-- on delete set null gracefully clears stale references when an org is
-- deleted.
alter table public.profile_settings
  add column if not exists active_org_id uuid
    references public.organizations(id) on delete set null;
